const pieza = $('Webhook Publish X').first().json.body.pieza;
const content = Buffer.from($json.content, 'base64').toString('utf8');
const lines = content.split('\n');

let xCopy = '', state = 0;
for (const line of lines) {
  if (state === 0 && line.trim() === '## X (Twitter)') { state = 1; continue; }
  if (state === 1 && line.trim() === '```') { state = 2; continue; }
  if (state === 2 && line.trim() === '```') break;
  if (state === 2) xCopy += (xCopy ? '\n' : '') + line;
}

if (!xCopy) throw new Error('No X copy block found in ' + pieza + '_PublishReady.md');
if (xCopy.length > 280) throw new Error('X copy too long: ' + xCopy.length + ' chars (max 280) for ' + pieza);

return [{ json: { pieza, xCopy } }];

const trackerRes = $input.first().json;
const bridgeRes = $('Publicar en X').first().json;
const copyData = $('Extraer X Copy').first().json;
const pieza = copyData.pieza;
const tweetId = bridgeRes.tweetId || bridgeRes.postId || null;
const tweetUrl = bridgeRes.url || (tweetId ? 'https://x.com/i/web/status/' + tweetId : null);

let tracker = {};
if (trackerRes.content) {
  try { tracker = JSON.parse(Buffer.from(trackerRes.content, 'base64').toString('utf8')); } catch(e) {}
}
const sha = trackerRes.sha || null;

const ahora = new Date().toISOString();
if (!tracker[pieza]) tracker[pieza] = { historial: [], publicaciones: [] };
tracker[pieza].historial = tracker[pieza].historial || [];
tracker[pieza].publicaciones = tracker[pieza].publicaciones || [];
tracker[pieza].historial.push({ estado: 'PUBLISHED', timestamp: ahora });
tracker[pieza].publicaciones.push({ plataforma: 'X', timestamp: ahora, ...(tweetId ? { tweetId } : {}), ...(tweetUrl ? { url: tweetUrl } : {}) });
tracker[pieza].estado_actual = 'PUBLISHED';
tracker[pieza].ultima_actualizacion = ahora;

const base64Content = Buffer.from(JSON.stringify(tracker, null, 2)).toString('base64');
return [{ json: { pieza, tweetId, tweetUrl, base64Content, ...(sha ? { sha } : {}) } }];

